mapper.insert:
INSERT IGNORE INTO learning_subject_state (
    owner_id, subject_type, subject_id, mastered, mastery_level, title_snapshot, keywords_snapshot,
    first_mastered_at, last_mastered_at, version, created_at, updated_at
) VALUES (
    #{ownerId}, #{subjectType}, #{subjectId}, #{mastered}, #{masteryLevel}, #{titleSnapshot},
    CAST(#{keywordsSnapshot} AS JSON), #{firstMasteredAt}, #{lastMasteredAt}, 1, #{createdAt}, #{updatedAt}
)

mapper.update:
UPDATE learning_subject_state
SET mastered = #{mastered},
    mastery_level = #{masteryLevel},
    title_snapshot = #{titleSnapshot},
    keywords_snapshot = CAST(#{keywordsSnapshot} AS JSON),
    first_mastered_at = CASE
        WHEN #{mastered} AND first_mastered_at IS NULL THEN #{updatedAt}
        ELSE first_mastered_at
    END,
    last_mastered_at = CASE WHEN #{mastered} THEN #{updatedAt} ELSE NULL END,
    version = version + 1,
    updated_at = #{updatedAt}
WHERE owner_id = #{ownerId}
  AND subject_type = #{subjectType}
  AND subject_id = #{subjectId}
  AND mastered <> #{mastered}

UPDATE learning_subject_state
SET title_snapshot = #{titleSnapshot},
    keywords_snapshot = CAST(#{keywordsSnapshot} AS JSON),
    source_deleted_at = #{sourceDeletedAt},
    version = version + 1,
    updated_at = #{sourceDeletedAt}
WHERE owner_id = #{ownerId}
  AND subject_type = #{subjectType}
  AND subject_id = #{subjectId}

