)

INSERT IGNORE INTO learning_plan (
    plan_id, owner_id, status, title, overview, estimated_minutes, generated_at, created_at, updated_at
) VALUES (
    #{planId}, #{ownerId}, 'ACTIVE', #{title}, #{overview}, #{estimatedMinutes},
