INSERT INTO learning_plan_step (
    step_id, plan_id, title, description, package_ids_snapshot, estimated_minutes,
    scheduled_date, actual_minutes, stage_label, reflection, status, position, completed_at
) VALUES (
    #{stepId}, #{planId}, #{title}, #{description}, CAST(#{packageIdsSnapshot} AS JSON),
    #{estimatedMinutes}, #{scheduledDate}, #{actualMinutes}, #{stageLabel}, #{reflection},
    #{status}, #{position}, #{completedAt}
)

mapper.update:
UPDATE learning_plan_step step
JOIN learning_plan plan ON plan.plan_id = step.plan_id
SET step.status = #{status},
    step.completed_at = #{completedAt},
    step.updated_at = #{updatedAt},
    plan.updated_at = #{updatedAt}
WHERE plan.owner_id = #{ownerId}
  AND plan.status = 'ACTIVE'
  AND step.step_id = #{stepId}

UPDATE learning_plan_step step
JOIN learning_plan plan ON plan.plan_id = step.plan_id
SET step.scheduled_date = #{scheduledDate},
    step.estimated_minutes = #{estimatedMinutes},
    step.reflection = #{reflection},
    step.updated_at = #{updatedAt},
    plan.updated_at = #{updatedAt}
WHERE plan.owner_id = #{ownerId}
  AND plan.status = 'ACTIVE'
  AND step.step_id = #{stepId}

mapper.insert:
INSERT INTO learning_plan_study_session (
    session_id, plan_id, step_id, minutes, note, studied_at, created_at
)
SELECT #{session.sessionId}, step.plan_id, step.step_id, #{session.minutes}, #{session.note},
       #{session.studiedAt}, #{session.createdAt}
FROM learning_plan_step step
JOIN learning_plan plan ON plan.plan_id = step.plan_id
WHERE plan.owner_id = #{ownerId}
  AND plan.status = 'ACTIVE'
  AND step.step_id = #{session.stepId}

mapper.update:
UPDATE learning_plan_step step
JOIN learning_plan plan ON plan.plan_id = step.plan_id
SET step.actual_minutes = step.actual_minutes + #{minutes},
    step.updated_at = #{updatedAt},
    plan.updated_at = #{updatedAt}
WHERE plan.owner_id = #{ownerId}
  AND plan.status = 'ACTIVE'
  AND step.step_id = #{stepId}

